public static void main(Args    _args)
{
    ETG_PurchaseShippingInstructionsController      purchShippingInstructionsController;
    ETG_PurchaseShippingInstructionsContract        purchShippingInstructionsContract;
    PurchAgreementHeader                            purchAgreementHeader;

    purchShippingInstructionsController =   ETG_PurchaseShippingInstructionsController::construct();
    purchAgreementHeader                =   _args.record() as PurchAgreementHeader;

    purchShippingInstructionsController =   new ETG_PurchaseShippingInstructionsController(
                                                classStr (ETG_PurchaseShippingInstructionsService),
                                                methodStr(ETG_PurchaseShippingInstructionsService , generateReportByGER),
                                                SysOperationExecutionMode::Synchronous);
    purchShippingInstructionsContract   =   purchShippingInstructionsController.getDataContractObject();

    purchShippingInstructionsContract.parmPurchaseAgreementId(purchAgreementHeader.PurchNumberSequence); // Setting the Value of agreement id

    purchShippingInstructionsController.parmArgs(_args);
    purchShippingInstructionsController.parmShowDialog(false);
    purchShippingInstructionsController.startOperation();
}
